func defaultPodcastShowsDir() string {
	configDir, err := os.UserConfigDir()
	if err != nil || configDir == "" {
		configDir = "."
	}
	return filepath.Join(configDir, "elevenlabs-pp-cli", "shows")
}

func readPodcastShowBible(path, show string) (podcastShowBible, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			return defaultPodcastShowBible(show), nil
		}
		return podcastShowBible{}, err
	}
	bible := defaultPodcastShowBible(show)
	currentSpeaker := ""
	for _, raw := range strings.Split(string(data), "\n") {
		line := strings.TrimSpace(raw)
		if line == "" || strings.HasPrefix(line, "#") {
			continue
		}
		key, value, ok := strings.Cut(line, ":")
		if !ok {
			continue
		}
		key = strings.TrimSpace(key)
		value = cleanPodcastScalar(value)
		switch key {
		case "slug":
			bible.Slug = value
		case "title":
			bible.Title = value
		case "tagline":
			bible.Tagline = value
		case "tone":
			bible.Tone = value
		case "audience":
			bible.Audience = value
		case "format":
			bible.Format = value
		case "model":
			bible.Model = value
		case "loudness":
			if parsed, err := strconv.ParseFloat(value, 64); err == nil {
				bible.Loudness = parsed
			}
		case "HOST", "GUEST":
			currentSpeaker = key
			if _, ok := bible.Cast[currentSpeaker]; !ok {
				bible.Cast[currentSpeaker] = ""
			}
		case "voice":
			if currentSpeaker != "" {
				bible.Cast[currentSpeaker] = value
			}
		case "persona":
			if currentSpeaker != "" {
				bible.Personas[currentSpeaker] = value
			}
		case "intro_music", "intro":
			bible.IntroPrompt = value
		case "outro_music", "outro":
			bible.OutroPrompt = value
		case "ambient_bed", "bed":
			bible.BedPrompt = value
		}
	}
	return bible, nil
}

